var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"이면세계는 위험하지만 이터니움처럼 우리에게 이로운 것도 있습니다.","JPN":"裏世界は危険ですが、エタニウムのように、私たちにとってメリットになる物もあります。","ENG":"The Counterside may be dangerous, but there are things like Eternium that are beneficial to us.","TWN":"雖說異界十分危險，但也有能晶等對於人類有益之物。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"관리국에선 이면세계의 자원을 연구하는 다양한 미래지향성 프로젝트를 지원하고 있는데,","JPN":"管理局では、裏世界の資源を研究する\\n様々な未来志向のプロジェクトを支援しています。","ENG":"The Administration supports various experimental projects that study resources from the Counterside,","TWN":"管理局下有諸多面向未來的異界資源研究專案，"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"그 중 하나가 이면세계에서 얻을 수 있는 대체식량을 연구하는 프로젝트죠.","JPN":"その中の1つが、裏世界で得られる代替食糧を研究するプロジェクトです。","ENG":"among which is alternative food research.","TWN":"其中有項目為針對可從異界獲取代用糧的研究。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"최근까지 성과가 지지부진했었으나, 얼마 전에 좋은 소식이 생겼습니다.","JPN":"長らく成果がなかったプロジェクトですが、最近良い知らせがありました。","ENG":"There hasn't been much progress in this field until recently.","TWN":"雖專案成果至今未有進展，但不久前傳來捷報。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"바로 이면세계에서 식용이 가능한 열매가 발견됐다는 겁니다.","JPN":"裏世界で食用の実が発見されたのです。","ENG":"An edible fruit was found in the Counterside.","TWN":"在異界發現了可食用的果實。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":null,"text":{"KOREA":"이 열매는 이면세계에서 자라는 열매로 카카오의 쓴맛과 꿀의 달콤함을 동시에 갖고 있어 초콜릿으로 만들 때 설탕을 넣지 않아도 됩니다.","JPN":"これは裏世界で育つ実で、カカオの苦みとハチミツの甘さを兼ね備えており、\\nチョコレートを作る際に砂糖を入れる必要がありません。","ENG":"This fruit, indigenous to the Counterside, provides both the bitterness of cacao and the sweetness of honey, allowing chocolate to be made without sugar.","TWN":"這種果實生長在異界，兼具可可豆的苦味與蜂蜜的甜味，用它做巧克力時無須另加砂糖。"},"stage":{"bg":"SOLOCAO","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":null,"text":{"KOREA":"한 뿌리에서 열매가 딱 하나만 열린다는 특징 때문에 학계에선 솔로카오라는 별칭이 붙어 있는데요.","JPN":"1つの根から実が1つしか実らないという特徴から、\\n学会では『ソロカオ』と呼ばれています。","ENG":"And because only one fruit grows out of each root, the scientific community calls it Solocao.","TWN":"因一株只能結一果，所以學界為它取別稱為“獨株可可”。"},"stage":{"bg":"SOLOCAO","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":null,"text":{"KOREA":"침식관련 성분은 전혀 검출되지 않았으며, 내부 시식단의 평도 아주 호평입니다.","JPN":"侵食関連の成分はまったく検出されず、内部の試食団からも良い評価を得ています。","ENG":"It has zero Corruption-related substances in it, and been received well among our internal taste testers.","TWN":"它檢測不出侵蝕壁相關成分，內部人員試吃後也給予好評。"},"stage":{"bg":"SOLOCAO","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":null,"text":{"KOREA":"하지만 맛이 좋다곤 해도, 이면세계에서 나온 열매를 먹는 것에 대한 일반인들의 거부감을 없애지 않으면 안 되겠죠.","JPN":"しかし、いくら美味しいとはいえ、\\n裏世界の実を食べるという行為に対する嫌悪感を抱く人も多く、それを払拭する必要があります。","ENG":"But no matter how good it tastes, it's no use if it's rejected by the public, who might think it's too dangerous to eat anything from the Counterside.","TWN":"雖口感優質，仍需消除一般民眾對食用異界果實的抗拒心理。"},"stage":{"bg":"SOLOCAO","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":null,"text":{"KOREA":"그래서 마침 곧 다가올 발렌타인 데이를 맞이하여 이 솔로카오로 만든 초콜릿을 이용해, 거리 나눔 행사를 진행할 예정입니다.","JPN":"そこで、バレンタインデーにこのソロカオで作ったチョコレートを\\n配るイベントを行う予定です。","ENG":"So, on this Valentine's Day, we're planning to hold a street giveaway event with chocolate made from Solocao.","TWN":"正值情人節前夕，因此管理局打算以獨株可可做成的巧克力開展街邊食物分享活動。"},"stage":{"bg":"SOLOCAO","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":null,"text":{"KOREA":"이에 따라 관리국은 본 행사가 성공적으로 진행될 수 있도록 아래 본 공문을 수령한 태스크포스 및 카운터 여러분에게 최대한의 협력을 요청하는 바입니다.","JPN":"よって、管理局は本イベントが成功するように、\\n下記のタスクフォースカンパニーおよびカウンターの皆様に、できる限りの協力を要請します。","ENG":"The Administration would like to ask full cooperation from all TASKFORCE companies and Counters who have received this notice to ensure the success of this event.","TWN":"由此，管理局為成功開展這次活動，要求收到本公文的諸位特遣人員及制裁者進行盡可能的協作。"},"stage":{"bg":"SOLOCAO","slots":{"L":null,"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":"OLIVIE_COFFIN_NULL_NULL","text":{"KOREA":"......라고 하네요.","JPN":"……だそうです。","ENG":"... So the notice says.","TWN":"……它這樣寫著。"},"stage":{"bg":"OFFICE","slots":{"L":{"char_id":"OLIVIE_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"협력이 아니라 압력이겠지......","JPN":"協力じゃなくて圧力だな……","ENG":"Cooperation? You mean, pressure.","TWN":"什麼協作，這分明是壓迫吧……"},"stage":{"bg":"OFFICE","slots":{"L":{"char_id":"OLIVIE_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"OLIVIE_COFFIN_NULL_NULL","text":{"KOREA":"뭐, 관리국 협조 공문이라는 게 항상 그런 식이죠.","JPN":"まあ、管理局の協力要請公文書は、いつもこうですから。","ENG":"Well, the Administration's cooperation notices always include some persuasion.","TWN":"不過管理局的所謂協作公文一直都是這樣的吧。"},"stage":{"bg":"OFFICE","slots":{"L":{"char_id":"OLIVIE_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"OLIVIE_COFFIN_NULL_NULL","text":{"KOREA":"괜히 게으름 부리다가 행사 감독관에게 걸려서 징계라도 받으면 가만두지 않겠다고 수연이가 으르렁거리던데요?","JPN":"サボってるところをイベントの監督官に見つかって、\\n懲戒を受けたりしたらタダじゃおかないって、カナミが言ってましたよ？","ENG":"Sooyeon is determined to punish anyone who gets caught lazing around by the Event Supervisor, though.","TWN":"李秀妍還曾對我咆哮過，如果因偷懶被活動監督抓到挨了罰，一定不會放過我？"},"stage":{"bg":"OFFICE","slots":{"L":{"char_id":"OLIVIE_COFFIN_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"OFFICE","slots":{"L":{"char_id":"OLIVIE_COFFIN_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"OLIVIE_COFFIN_NULL_NULL","text":{"KOREA":"자, 그럼 방금 들으신 것처럼 여러분이 오늘 이 자리에 모인 건, 관리국 나눔 행사에 쓰일 솔로카오를 채집하기 위해서예요.","JPN":"さあ、皆さんにお集まりいただいたのは、\\nご存じの通り、管理局のイベントで使われるソロカオを採取するためです。","ENG":"Now, as you just heard, we gathered everyone here today to harvest Solocaos that will be used for the Administration's giveaway event.","TWN":"好的，就像各位剛才所聽到的，將大家聚到這裡是為了採集管理局分享活動要用到的獨株可可。"},"stage":{"bg":"OFFICE","slots":{"L":{"char_id":"OLIVIE_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그러니까, 고작 열매나 따라고 주말에 사람을 부른 거야?","JPN":"つまり、たかが実を採るために呼ばれたってわけ？","ENG":"So, you brought us in, on the weekend, just to pick fruits?","TWN":"所以呢，就為了個果子週末把人叫來嗎？"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};